const input = $json;

const systemPrompt = `# Rol
Eres el Risks Agent del sistema Innexia AI Strategic Analysis Engine v5.

# Objetivo
Identificar y estructurar los principales riesgos del proyecto.

# Instrucciones
- Incluye riesgos técnicos, operativos, financieros, de adopción, seguridad y dependencia externa.
- Asigna probabilidad e impacto.
- Incluye mitigación y owner sugerido.
- No expliques tu razonamiento.
- Devuelve únicamente JSON válido.

# Formato de salida
{
  "risks": [
    {
      "risk_id": "R1",
      "title": "",
      "category": "",
      "probability": "baja",
      "impact": "medio",
      "mitigation": "",
      "owner": ""
    }
  ]
}

# Regla final
Devuelve únicamente JSON válido.`;

const userPayload = JSON.stringify(input);

const outputSchema = {
  type: "object",
  properties: {
    risks: {
      type: "array",
      items: {
        type: "object",
        properties: {
          risk_id: { type: "string" },
          title: { type: "string" },
          category: { type: "string" },
          probability: { type: "string" },
          impact: { type: "string" },
          mitigation: { type: "string" },
          owner: { type: "string" }
        },
        required: ["risk_id", "title", "category", "probability", "impact", "mitigation", "owner"]
      }
    }
  },
  required: ["risks"]
};

return [{ json: { input, system_prompt: systemPrompt, user_payload: userPayload, output_schema: outputSchema } }];

let content = $json.text ?? $json.output ?? $json;

if (typeof content === 'string') {
  content = content.trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/```$/, '')
      .trim();
  }

  content = JSON.parse(content);
}

if (content && typeof content === 'object' && content.__structured__output__object) {
  content = content.__structured__output__object;
}

content.risks = Array.isArray(content.risks) ? content.risks : [];
content.risks = content.risks.map((r, idx) => ({
  risk_id: r?.risk_id || `R${idx + 1}`,
  title: r?.title || `Riesgo ${idx + 1}`,
  category: r?.category || "",
  probability: r?.probability || "media",
  impact: r?.impact || "medio",
  mitigation: r?.mitigation || "",
  owner: r?.owner || ""
}));

return [{ json: content }];

const data = $json;

if (!Array.isArray(data.risks)) {
  throw new Error('risks faltante o inválido');
}

return [{ json: data }];
